code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Avatar, Badge, Button, Select, icon } from 'decantr/components';

code.example:
function TeamMemberRow({ member, isAdmin, onChangeRole, onRemove }) {
  const { div, span } = tags;
  const roleVariant = { owner: 'primary', admin: 'secondary', member: 'outline' };

  return div({ class: css('_flex _aic _gap4 _px4 _py4 _borderb _bordermuted/10') },
    Avatar({ src: member.avatar, name: member.name, size: 'md' }),
    div({ class: css('_flex _col _gap1 _flex1 _min-w0') },
      span({ class: css('_textsm _fontmedium _truncate') }, member.name),
      span({ class: css('_textxs _fgmuted _truncate') }, member.email)
    ),
    Badge({ variant: roleVariant[member.role] || 'outline', size: 'sm' }, member.role),
    span({ class: css('_textxs _fgmuted _shrink0') }, `Joined ${member.joined_at}`),
    isAdmin && member.role !== 'owner'
      ? div({ class: css('_flex _gap2 _shrink0') },
          Select({ size: 'sm', value: member.role, onchange: (e) => onChangeRole(member.id, e.target.value) },
            { value: 'admin', label: 'Admin' },
            { value: 'member', label: 'Member' }
          ),
          Button({ variant: 'ghost', size: 'sm', onclick: () => onRemove(member.id) },
            icon('user-minus', { size: '0.875rem', class: css('_fgdestructive') })
          )
        )
      : null
  );
}

