function TeamMemberRowInvite({ invite, onResend, onCancel }) {
  const { div, span } = tags;

  return div({ class: css('_flex _aic _gap4 _px4 _py3 _borderb _bordermuted/10 _bgmuted/5') },
    icon('mail', { size: '1.25rem', class: css('_fgmuted') }),
    span({ class: css('_textsm _flex1') }, invite.email),
    Badge({ variant: 'warning', size: 'xs' }, `Expires ${invite.expires_at}`),
    div({ class: css('_flex _gap2') },
      Button({ variant: 'ghost', size: 'xs', onclick: () => onResend(invite.id) }, icon('refresh-cw', { size: '0.75rem' }), ' Resend'),
      Button({ variant: 'ghost', size: 'xs', onclick: () => onCancel(invite.id) }, icon('x', { size: '0.75rem' }), ' Cancel')
    )
  );
